$(document).ready(function(){var e=$(".offcanvas"),n=$(".offcanvas-toggle");$(n).on("click",function(){e.toggleClass("offcanvas--opened")}),$(".side-menu-close").on("click",function(){e.removeClass("offcanvas--opened")}),$(document).on("click",function(o){$(o.target).is(e)||$(o.target).closest(e).length||$(o.target).is(n)||$(o.target).closest(n).length||e.removeClass("offcanvas--opened")})});